patch:
diff --git a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
index 456f5086309c..145e20da912e 100644
--- a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
+++ b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
@@ -1127,6 +1127,10 @@ void State::addInfoFor(BasicBlock &BB) {
       WorkList.push_back(
           FactOrCheck::getCheck(DT.getNode(&BB), cast<CallInst>(&I)));
       break;
+    case Intrinsic::usub_sat:
+      WorkList.push_back(
+          FactOrCheck::getInstFact(DT.getNode(&BB), &I));
+      break;
     // Enqueue the intrinsics to add extra info.
     case Intrinsic::umin:
     case Intrinsic::umax:
@@ -1898,6 +1902,14 @@ static bool eliminateConstraints(Function &F, DominatorTree &DT, LoopInfo &LI,
         AddFact(Pred, MinMax, MinMax->getRHS());
         continue;
       }
+
+      Value *Y;
+      if (match(CB.Inst, m_Intrinsic<Intrinsic::usub_sat>(m_Value(X), m_Value(Y)))) {
+        AddFact(CmpInst::ICMP_ULE, CB.Inst, X);
+        // usub.sat(X, Y) decomposes to X - Y for constraint system. No wait, usub.sat doesn't decompose yet!
+        // Let's check how decompose() works.
+        continue;
+      }
     }

     Value *A = nullptr, *B = nullptr;

